30	void SimpleRLMoveGenerator::process_outcome(double reward, e_reward_function reward_fun) {
31	    karmed_bandit_agent->process_outcome(reward, reward_fun);
32	}
33	
34	/*                                        *
35	 *                                        *
36	 *  K-Armed bandit agent implementation   *
37	 *                                        *
38	 *                                        */
39	KArmedBanditAgent::KArmedBanditAgent(std::vector<e_move_type> available_moves,
40	                                     e_agent_space agent_space,
41	                                     vtr::RngContainer& rng,
42	                                     const std::vector<int>& num_movable_blocks_per_type)
43	    : available_moves_(std::move(available_moves))
44	    , propose_blk_type_(agent_space == e_agent_space::MOVE_BLOCK_TYPE)
45	    , rng_(rng) {
46	    std::vector<int> available_logical_block_types = get_available_logical_blk_types_(num_movable_blocks_per_type);
47	    num_available_types_ = available_logical_block_types.size();
48	
49	    size_t num_available_moves = available_moves_.size();
50	    num_available_actions_ = propose_blk_type_ ? (num_available_moves * num_available_types_) : num_available_moves;
51	
52	    action_logical_blk_type_.clear();
53	
54	    for (auto logical_blk_type_idx : available_logical_block_types) {
55	        action_logical_blk_type_.push_back(logical_blk_type_idx);
56	    }
57	}
58	
59	/*
60	 * If the agent selects both move type and block type, the action table would look like this:
61	 *
62	 *    +---------------+---------------+---------------+---------------+
63	 *    | (blk0, move0) | (blk0, move1) | ............. | (blk0, moveN) |
64	 *    +---------------+---------------+---------------+---------------+
65	 *    | (blk1, move0) | (blk1, move1) | ............. | (blk1, moveN) |
66	 *    +---------------+---------------+---------------+---------------+
67	 *    |      ..       |       ..      | ............. |       ..      |
68	 *    +---------------+---------------+---------------+---------------+
69	 *    | (blkK, move0) | (blkK, move1) | ............. | (blkK, moveN) |
70	 *    +---------------+---------------+---------------+---------------+
71	 *
72	 *    This meant that (action_idx % num_available_moves_) specifies the move type,
73	 *    while (action_idx / num_available_moves_) determines the block type.
74	 *
75	 */
76	e_move_type KArmedBanditAgent::action_to_move_type_(const size_t action_idx) {
77	    e_move_type move_type = e_move_type::INVALID_MOVE;
78	
79	    if (action_idx < num_available_actions_) {
80	        move_type = available_moves_[action_idx % available_moves_.size()];
81	    }
82	
83	    return move_type;
84	}
85	
86	int KArmedBanditAgent::action_to_blk_type_(const size_t action_idx) {
87	    if (propose_blk_type_) {
88	        return action_logical_blk_type_.at(action_idx / available_moves_.size());
89	    } else { // the agent doesn't select the move type
90	        return -1;
91	    }
92	}
93	
94	std::vector<int> KArmedBanditAgent::get_available_logical_blk_types_(const std::vector<int>& num_movable_blocks_per_type) {
95	    const auto& device_ctx = g_vpr_ctx.device();
96	
97	    std::vector<int> available_blk_types;
98	
99	    for (const auto& logical_blk_type : device_ctx.logical_block_types) {
100	        if (logical_blk_type.index == 0) { //ignore empty type
101	            continue;
102	        }
103	
104	        int num_blk_per_type = num_movable_blocks_per_type[logical_blk_type.index];
105	
106	        if (num_blk_per_type > 0) {
107	            available_blk_types.push_back(logical_blk_type.index);
108	        }
109	    }
110	
111	    // when there is no movable blocks, RL agent always selects the empty logical block
112	    // since there are no empty blocks in the netlist, the move is always aborted
113	    if (available_blk_types.empty()) {
114	        available_blk_types.push_back(device_ctx.EMPTY_LOGICAL_BLOCK_TYPE->index);
115	    }
116	
117	    return available_blk_types;
118	}
119	
120	void KArmedBanditAgent::process_outcome(double reward, e_reward_function reward_fun) {
121	    ++num_action_chosen_[last_action_];
122	    if (reward_fun == e_reward_function::RUNTIME_AWARE || reward_fun == e_reward_function::WL_BIASED_RUNTIME_AWARE) {
123	        e_move_type move_type = action_to_move_type_(last_action_);
124	        reward /= time_elapsed_[move_type];
125	    }
126	
127	    //Determine step size
128	    float step = 0.;
129	    if (exp_alpha_ < 0.) {
130	        step = 1.0f / (float)num_action_chosen_[last_action_]; //Incremental average
131	    } else if (exp_alpha_ <= 1) {
132	        step = exp_alpha_; //Exponentially weighted average
133	    } else {
134	        VTR_ASSERT_MSG(false, "Invalid step size");
135	    }
136	
137	    //Based on the outcome how much should our estimate of q change?
138	    float delta_q = step * (reward - q_[last_action_]);
139	
