168	    if (gamma < 0) {
169	        exp_alpha_ = -1; //Use sample average
170	    } else {
171	        //
172	        // For an exponentially weighted average the fraction of total weight applied
173	        // to moves which occurred > K moves ago is:
174	        //
175	        //      gamma = (1 - alpha)^K
176	        //
177	        // If we treat K as the number of moves per temperature (move_lim) then gamma
178	        // is the fraction of weight applied to moves which occurred > move_lim moves ago,
179	        // and given a target gamma we can explicitly calculate the alpha step-size
180	        // required by the agent:
181	        //
182	        //     alpha = 1 - e^(log(gamma) / K)
183	        //
184	        float alpha = 1 - std::exp(std::log(gamma) / move_lim);
185	        exp_alpha_ = alpha;
186	    }
