313	void SoftmaxAgent::init_q_scores_(const std::vector<int>& num_movable_blocks_per_type) {
314	    q_ = std::vector<float>(num_available_actions_, 0.);
315	    exp_q_ = std::vector<float>(num_available_actions_, 0.);
316	    num_action_chosen_ = std::vector<size_t>(num_available_actions_, 0);
317	    action_prob_ = std::vector<float>(num_available_actions_, 0.);
318	    block_type_ratio_ = std::vector<float>(num_available_types_, 0.);
319	    cumm_action_prob_ = std::vector<float>(num_available_actions_);
320	
321	    //    agent_info_file_ = vtr::fopen("agent_info.txt", "w");
322	    //write agent internal q-table and actions into file for debugging purposes
323	    if (agent_info_file_) {
324	        //we haven't performed any moves yet, hence last_aciton and reward are 0
325	        write_agent_info(0, 0);
326	    }
327	
328	    /*
329	     * The agent calculates each block type ratio as: (# blocks of each type / total blocks).
330	     * If the agent is supposed to propose both block type and move type,
331	     * it will use the block ratio to calculate action probability for each q_table entry.
332	     */
333	    if (propose_blk_type_) {
334	        set_block_ratio_(num_movable_blocks_per_type);
335	    }
336	    set_action_prob_();
337	}
