339	t_propose_action SoftmaxAgent::propose_action() {
340	    set_action_prob_();
341	
342	    float p = rng_.frand();
343	    auto itr = std::lower_bound(cumm_action_prob_.begin(), cumm_action_prob_.end(), p);
344	    auto action_type_q_pos = itr - cumm_action_prob_.begin();
345	    //To take care that the last element in cumm_action_prob_ might be less than 1 by a small value
346	    last_action_ = std::min((size_t)action_type_q_pos, num_available_actions_ - 1);
347	
348	    t_propose_action proposed_action{action_to_move_type_(last_action_),
349	                                     action_to_blk_type_(last_action_)};
350	
351	    //Check the move type to be a valid move
352	    VTR_ASSERT_SAFE(std::find(available_moves_.begin(), available_moves_.end(), proposed_action.move_type) != available_moves_.end());
353	
354	    return proposed_action;
355	}
